var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"크으윽……!","JPN":"くううっ……！","ENG":"Urgh...!","TWN":"咳呃呃……！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"더 이상은 못 참아! 대체 언제까지 내가 네 녀석들 뒷바라지를 해야 하는 거냐!","JPN":"もう我慢の限界だ！　いつまであんたらの世話をしなきゃならないんだ！","ENG":"I can't take it anymore! How long am I supposed to babysit you people?!","TWN":"我再也忍不住了！我到底要照顧你們這些傢伙到什麼時候！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"너희들이 들러붙은 뒤로 사무실에 하와이안 피자 냄새가 진동한다고!","JPN":"あんたらが居候し出してから、すっかり事務所にハワイアンピザの匂いが染みついちまった！","ENG":"Ever since you latched on, the office reeks of Hawaiian pizza!","TWN":"自從你們待在這裡之後，整個辦公室都是夏威夷披薩的味道！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그것 참 멋진 일이군. 이 참에 별명을 스마트가이에서 스위트가이로 바꾸는 건 어때?","JPN":"そりゃよかったな。これを機にコールサインをスマートガイからスイートガイに変えるのはどうだ？","ENG":"How charming. How about changing your nickname from Smart Guy to Sweet Guy?","TWN":"這是件很棒的事，趁這機會把綽號從聰明男孩改成甜美男孩怎麼樣？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"달콤한 파인애플만큼 멋진 이름이라고 생각하는데.","JPN":"甘いパイナップルのように素敵な名前だと思うが。","ENG":"I think it's as sweet as a pineapple.","TWN":"我覺得這稱號就像香甜的鳳梨一樣美好。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"괜찮은데? 요즘 젊은 애들은 딱딱한 남자보다 달콤한 듯 부드러운 남자를 선호한다고.","JPN":"いいんじゃないか。最近の若者にはお堅い男よりは甘くて柔らかい男がモテるんだぜ。","ENG":"Sounds good to me. Kids these days prefer guys who are sweet and soft over stiff types.","TWN":"不錯耶？聽說最近年輕人比起死板的男人，更喜歡甜美溫柔的男人。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L14_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"그래. 먹다 보니 이 피자도 나름 괜찮고 말이야.","JPN":"そうそう。食べ慣れるとこのピザも結構うまいしな。","ENG":"Yeah. And you know, this pizza isn't half bad once you keep eating it.","TWN":"沒錯，吃到後來也覺得這個披薩很不錯。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"군인 놈들은 평시에도 전투식량이나 먹어댈 줄 알았는데, 제법 센스가 괜찮잖아?","JPN":"軍人のやつらは戦場以外でも戦闘食糧ばっかり食ってるもんだと思ってたけど、なかなかいいセンスしてるな。","ENG":"I figured soldiers ate MREs even off duty, but you've actually got taste.","TWN":"我還以為軍人平常也都是吃野戰口糧，但還滿有品味的嘛？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"용병 치고는 뭘 좀 아네, 형씨. 어디 사는 스마트가이보다 백 번 나아.","JPN":"傭兵の割に分かってるじゃないか。どこぞのスマートガイよりずっとマシだ。","ENG":"For a merc, you know a thing or two, pal. You're a hundred times better than a certain Smart Guy I know.","TWN":"就傭兵而言，你還挺懂的，老兄。比住在某個地方的聰明男孩好一百倍。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"아니, 이젠 스위트가이인가?","JPN":"いや、スイートガイと呼ぶべきか？","ENG":"Or is it Sweet Guy now?","TWN":"等等，現在是甜美男孩嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"하하하!!","JPN":"ははは！！","ENG":"Hahaha!!","TWN":"哈哈哈！！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이렇게는 못살아! 여긴 내 사무실이란 말이다!!","JPN":"こんな生活やってられるか！　ここは俺の事務所だぞ！！","ENG":"I can't live like this! This is my office!","TWN":"我沒辦法這ˋ樣過下去！這裡可是我的辦公室！！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"진정하세요. 저래도 들러붙은 값만큼은 톡톡히 치르고 있잖아요?","JPN":"落ち着いてください。あれでも居候してる分は働いてもらってるじゃありませんか。","ENG":"Easy, boss. For how much she's been glued to us, she's at least paying her \\"cling fee,\\" yeah?","TWN":"冷靜點，至少他們待在這裡付的錢也不少吧？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"요즘 벌이도 시원찮은데, 하와이안 피자 정도면 점심으로는 나름 호화스럽죠.","JPN":"最近売上も落ちているのに、ハワイアンピザなら十分豪華な昼食です。","ENG":"Business has been trash lately. A Hawaiian pizza for lunch? That's downright luxury.","TWN":"最近錢也不好賺，夏威夷披薩當作午餐也算豪華了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"……파인애플만 빼면, 어쨌든 피자니까.","JPN":"……パイナップルが乗っているというだけで、ピザはピザですから。","ENG":"...Pineapple crimes aside, pizza's still pizza.","TWN":"……撇除鳳梨不說，總之是披薩。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그래, 메이슨 씨. 좋은 게 좋은 거야.","JPN":"そうだぞ、メイソンさんよ。ポジティブ思考が一番ってことさ。","ENG":"Let good enough be good enough, Mr. Mason.","TWN":"是啊，梅森，就別再挑剔了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"이 달콤함에 거스를 생각 말고 시대의 흐름에 합류하라고.","JPN":"この甘さに逆らわず、時代の流れに身を委ねろ。","ENG":"Stop fighting the sweetness and join the times.","TWN":"別想抗拒這份甜蜜，要加入時代的潮流。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"시대의 흐름이고 자시고, 군인이 이렇게 놀고먹기만 해도 되는 건가?","JPN":"時代の流れはともかく、軍人がこうやって暇してていいのか？","ENG":"Trend or not, are soldiers really allowed to loaf around like this?","TWN":"管他什麼時代的潮流，軍人可以這樣游手好閒嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"알면서 뭘 그래? 델타 세븐은 클리포트 게임 당시 검은 평의회와 협력했다고.","JPN":"知ってるだろう？　デルタセブンはクリフォトゲーム当時、黒い評議会に協力した。","ENG":"You know the score. Delta Seven teamed up with the Dark Council during the Qliphoth Game.","TWN":"你明知道幹嘛還這樣？ 第七三角洲在逆卡巴拉遊戲當時和黑暗評議會合作了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그런 범죄조직이랑 손을 잡았으니, 높으신 분들의 비위가 어련하겠어?","JPN":"犯罪組織と手を組んだのに、上の方々の機嫌が良いわけないだろ？","ENG":"We shook hands with a crime syndicate. The bigwigs aren't exactly thrilled.","TWN":"既然已經和那種犯罪組織聯手，還能怎麼討好上位的人？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"세상을 구한 일은 뒷전으로 미루고 당장 무기한 근신처분이 내려와도 어쩔 수 없지.","JPN":"世界を救った功績を称えるより先に、無期限謹慎処分を下されても仕方ない。","ENG":"Even if saving the world gets brushed aside, an indefinite suspension was bound to land.","TWN":"就算把拯救世界的事拋諸腦後，立即下達無限期停職處分也沒辦法。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 말은, 징계를 받았으면 반성하는 기미를 보이란 말이야.","JPN":"俺が言いたいのは、懲戒を受けているなら反省しているふりでもしろってことだ。","ENG":"My point is, if you're disciplined, at least act like you're reflecting.","TWN":"我的意思是既然受到懲處，就要展現出反省之意。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 사무실을 본인 비밀기지처럼 들락거리지 말고!","JPN":"さも自分の秘密基地のように俺の事務所に出入りするんじゃなくてな！","ENG":"And stop treating my office like your secret base!","TWN":"不要把我辦公室當成自己的秘密基地一樣進進出出！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그건 어렵겠군. 부대에서는 카일이랑 실비아 눈치 보느라 이렇게 지낼 수가 없다고.","JPN":"それは無理だな。部隊だとカイルとシルビアの目が気になってくつろげないんだ。","ENG":"That's tough. Back on base I have to watch Kyle and Sylvia breathing down my neck.","TWN":"這應該很難，因為在部隊裡要看凱爾和希爾維亞的臉色，沒辦法這樣生活。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"근신을 휴가처럼 사용하지 마!","JPN":"謹慎は休暇じゃないんだぞ！","ENG":"Don't treat a suspension like a vacation!","TWN":"不要把停職當休假一樣使用！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"폰 진동음? 설마 의뢰 요청인가?","JPN":"携帯の振動？　まさか依頼が来たのか？","ENG":"Phone vibrating? Don't tell me it's a job request.","TWN":"手機震動？難道是委託請求？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L43_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"유감이지만 저쪽 대령님 폰이네요.","JPN":"残念ですが、あちらの大佐の携帯ですね。","ENG":"Hate to break it to you, but that's the Colonel's phone.","TWN":"雖然很遺憾，但那是上校的手機。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"발신자 표시 제한인데 끊을까요?","JPN":"発信者不明ですが、切りましょうか？","ENG":"Caller ID's blocked. Should I just kill the call?","TWN":"沒有來電顯示，要不要掛掉？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그건 안 돼, 아가씨. 이래봬도 높으신 분들에게 제법 인기있는 편이거든.","JPN":"それはいけない、嬢ちゃん。こう見えて俺はお偉いさんたちにモテるんでね。","ENG":"Can't do that, miss. Like it or not, the bigwigs kind of like me.","TWN":"不行，小姐，別看我這樣，我很受上頭歡迎。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"뭐, 지금 상황에서 호출 받을 일은 없겠지만.","JPN":"ま、今の状況で呼び出されるなんて、ないと思うが。","ENG":"Though no one will be calling me in under these circumstances.","TWN":"嗯，雖然現在這情況下應該不會被呼叫。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"이런, 아무래도 귀찮은 일에 휘말린 것 같은데.","JPN":"はあ、どうやら厄介なことに巻き込まれてしまったようだな。","ENG":"Well, looks like we just got dragged into a pain in the neck.","TWN":"哎呀，總覺得是被捲入麻煩事了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"흥. 그럼 그렇지. 세금으로 일하는 공무원이면 가서 일이나 해.","JPN":"ふん、ざまあ見ろ。税金で食ってる公務員はとっとと仕事に戻れ。","ENG":"Hmph. Figures. If you're a taxpayer-paid civic servant, go do your job.","TWN":"嗯，我想也是。領稅金工作的公務員就去做你的工作吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"메이슨 씨. 사람 말은 끝까지 듣는 편이 좋아.","JPN":"メイソンさん、人の話は最後まで聞いたほうがいい。","ENG":"Mason, it helps to hear people out before you jump to conclusions.","TWN":"梅森，還是把別人的話聽完比較好。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"귀찮은 일에 휘말린 건, <color=#ffd34c>우리</color>라고.","JPN":"厄介なことに巻き込まれちまったのは、<color=#ffd34c>俺たち</color>だ。","ENG":"The ones getting dragged in are <color=#ffd34c>us</color>.","TWN":"被捲入麻煩事的人是<color=#ffd34c>我們</color>。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"짐 챙기고 떠날 준비해.","JPN":"荷造りして、出かける準備だ。","ENG":"Pack up and get ready to move.","TWN":"收拾好行李，準備出發。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"기왕이면, 언제든 싸울 수 있는 만전의 상태로.","JPN":"できれば、いつでも戦える万全の状態でな。","ENG":"Preferably at full readiness to fight at any time.","TWN":"既然這樣，就要保持隨時能戰鬥，萬無一失的狀態。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"subtitle","speaker":null,"text":{"KOREA":"미합중국 대통령 관저\\n델타 세븐 비상소집 발령, 1시간 뒤.","JPN":"アメリカ合衆国大統領官邸\\nデルタセブン非常招集発令、1時間後。","ENG":"The States' President Residence\\nDelta Seven Emergency Call, one hour later.","TWN":"美合眾國總統官邸\\n發布第七三角洲緊急集合命令，一小時後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"충성. 오랜만에 뵙습니다, 대통령님.","JPN":"お久しぶりです、大統領。","ENG":"Salute. It has been a while, Mr. President.","TWN":"忠誠，好久不見了，總統。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그래. 검은 평의회와의 건으로 자네가 싫어하는 정치 문제에 얽혀 고생인 줄 알았는데.","JPN":"ああ。黒い評議会との件で、苦手な政治問題に関わって苦労しているかと思ったが。","ENG":"Right. I figured you were suffering, tangled in the politics you hate because of the Dark Council affair.","TWN":"是啊，我還以為妳因為和黑暗評議會的事被扯進政治問題吃了不少苦，"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"얼굴색은 이전보다 좋군. 이번 공백이 부대 분위기를 얼추 환기시킨 모양이야.","JPN":"以前よりは顔色が良いようだな。今回のブランクが、部隊にとっても気分転換になったのか？","ENG":"But you look better than before. The downtime seems to have aired out the unit.","TWN":"但臉色比之前還好，看來這次空檔大概改變了部隊的氣氛。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다들 내색하진 않아도 사명감이 투철하니 말입니다.","JPN":"皆表に出さないだけで、使命感の強い者たちですから。","ENG":"Even if they don't show it, their sense of duty runs deep.","TWN":"就算大家沒有表露出來，但都有強烈的使命感。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 사태부터 쉽지 않은 역경의 연속이었으니…….","JPN":"リプレイサー事件から逆境続きでしたし……","ENG":"It has been one ordeal after another since the Replacer incident...","TWN":"從克隆集團的事開始就連續遭遇艱難的逆境……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"근신 처분이라도 내려오지 않는 한, 무리해서라도 싸움을 이어갔겠죠.","JPN":"謹慎処分でも受けない限り、無理をしてでも戦い続けていたでしょう。","ENG":"If not for the suspension, they would have kept fighting even by pushing themselves.","TWN":"只要沒有下達停職處分，即使勉強自己也要繼續戰鬥。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그렇다면 구태여 쉬고 있는 자네들을 소집한 이유도 예상했겠군.","JPN":"では、あえて休暇中の君たちを呼び出した理由も見当がついていそうだな。","ENG":"Then you can probably guess why I recalled you while you were resting.","TWN":"這樣的話，妳應該也有料到我為什麼非要召集你們這些在休息的人。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"빈손으로 관저에 들른 게, 약간의 불만 표현이라고 생각해주시면 좋겠군요.","JPN":"手ぶらで官邸に来たのは、若干の不満の現れだと思ってください。","ENG":"Consider coming empty-handed my little show of displeasure.","TWN":"希望您能將我空手來到官邸，當作是種表達些微不滿的方式。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"이해해주게. 나도 갑작스레 연락 받은 상황이라 말이야.","JPN":"理解してくれ。私も急に連絡を受けてね。","ENG":"I understand. I was contacted out of the blue myself.","TWN":"請妳體諒，我也是突然接到通知。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"미합중국의 대통령이라도 이곳저곳에서 휘둘리는 편일세.","JPN":"アメリカ合衆国の大統領といっても、あちこち振り回されているのだよ。","ENG":"Even the States' President gets jerked around from all sides.","TWN":"即使是美合眾國總統，也會四處受人擺布。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_QM","text":{"KOREA":"휘둘리긴 무슨. 높으신 양반이 부하들 앞에서 잘도 그런 말을 하네.","JPN":"振り回される？　ふん、部下の前でよくそんなことが言えるわね。","ENG":"Jerked around, my foot. Pretty absurd hearing that in front of your subordinates.","TWN":"受什麼擺布？位居高位之人在部下面前居然還說那樣的話。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자 봐, 대통령 아저씨. 여기 플레이 타임이 0시간인 게임들이 보여?","JPN":"ほら大統領さん。ここ、見える？　プレイ時間が0のゲームの数々が。","ENG":"Look, Mr. President. See these games with zero hours played?","TWN":"你看，總統大叔，有看到這些進行時間0小時的遊戲嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"다른 사람한테 휘둘린다는 건 이런 거야. 일하느라 여가시간이 없는 슬픈 삶이라고.","JPN":"他人に振り回されるってのはこういうことよ。働きすぎて趣味を楽しむ時間がない悲しい人生なの。","ENG":"That is what being jerked around looks like. A sad life with no leisure because of work.","TWN":"這才叫受人擺布，顧著工作都沒有閒暇時間的悲傷生活。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"게임의 플레이타임만 그렇지, 실상 롬파일을 개조하는데 여가시간을 할애하잖습니까.","JPN":"ゲームのプレイ時間は0でも、実際はROMファイルの改造に時間を費やしているではありませんか。","ENG":"Only the playtime is zero. In reality you spend your free time modding ROM files.","TWN":"只有遊戲的進行時間是這樣，實際上不是把閒暇時間花在改造ROM檔案上嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"야, 이건 봉사활동이야. 개발실에 역수출된 코드도 있으니 나름 선순환이라고.","JPN":"あのね、これはボランティアなの。開発室に逆輸出したコードもあるし、好循環よ？","ENG":"Hey, that is community service. Some of that code even got re-imported to the dev studio. Circle of life.","TWN":"喂，這是志願活動。也有被逆向輸出到開發室的代碼，所以算是良性循環。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"주구장창 꼬여버린 스파게티 코드를 정상화해주는 유저가 세상 어딨겠어?","JPN":"こんがらがっちゃったスパゲティコードを正常化してくれるユーザーなんて、そうそういないんだから。","ENG":"Who else on earth cleans up spaghetti code that has been tangled for ages?","TWN":"世上哪有能讓錯綜複雜的麵條式代碼正常化的用戶？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그것보다, 버터맨이랑 우유걸은?","JPN":"それより、バターマンとミルクガールは？","ENG":"More importantly, where are Sleazeball and Milk Girl?","TWN":"比起這個，奶油男和牛奶女呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"둘이라면 장비 관리실에 있네.","JPN":"2人は装備管理室にいる。","ENG":"The two of them are in the gear bay.","TWN":"他們兩個在裝備管理室。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"워커 대령과 크로펠 소령은 델타 세븐의 핵심 전력인만큼, 장비 점검절차가 까다롭거든.","JPN":"ウォーカー大佐とクロペル少佐はデルタセブンの要となる戦力だけあって、装備の点検手続きも厳しいんでね。","ENG":"Colonel Walker and Major Kropel are core to Delta Seven, so the checks are strict.","TWN":"沃克上校和克洛佩爾少校是第七三角洲的核心戰力，裝備檢查程序十分繁瑣。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"장비? 갑자기 그건 뭣 하러 챙겨?","JPN":"装備？　急になんで装備が必要なの？","ENG":"Gear? What are they getting ready for?","TWN":"裝備？突然拿那個幹嘛？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"No way...","TWN":"難道……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그래. 현시간부로 델타 세븐의 무기한 근신 처분이 해제되었네.","JPN":"ああ。現時刻をもってデルタセブンの無期限謹慎処分が解除された。","ENG":"Yes. As of now, Delta Seven's indefinite suspension is lifted.","TWN":"沒錯，從現在起，第七三角洲的無限期停職處分已經解除。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"자네들은 다시금 합중국 전략특수전사령부 소속으로서 임무를 수행하게 될 거야.","JPN":"君たちには再び、合衆国の戦略特殊戦司令部所属として任務を遂行してもらう。","ENG":"You will resume missions under the States Strategic Special Operations Command.","TWN":"你們要再次以合眾國戰略特種作戰司令部所屬的身分執行任務。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"켁.","JPN":"げっ。","ENG":"Egh.","TWN":"咳。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"얼추 예상했지만, 갑작스러운 비상소집은 이것 때문이었군요.","JPN":"おおかた予想はしていましたが、突然の非常招集はこれのためだったのですね。","ENG":"I half expected it, so the sudden emergency call was because of this.","TWN":"雖然大概料到了，但原來突然緊急召集是因為這樣。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"상부에서 평의회와 손을 잡은 저희들의 편을 들어준 것을 보면…….","JPN":"評議会と手を組んだ僕たちを、上層部が庇ってくれた理由は……","ENG":"If the higher-ups sided with us even after we worked with the Council...","TWN":"從上級站在和評議會聯手的我們這邊看來……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"외교적인 문제를 차치해서라도, 당장 막아야만 하는 위험요소가 있다는 뜻이겠죠.","JPN":"外交的な問題を後回しにしてでも、阻止せねばならない緊急の危険要素があるということでしょう。","ENG":"It means there is an immediate threat we must stop, diplomacy aside.","TWN":"意思應該是姑且不論ˋ外交問題，也有必須立即阻止的危險因素。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나도 알거든? 결국 귀찮은 일이 생겼다는 거잖아!","JPN":"アタシもわかってるわよ。つまり、面倒事が起きたってことじゃない！","ENG":"Yeah, yeah, I know. It means we got stuck with something annoying!","TWN":"我也知道好嗎？到頭來不就是發生麻煩事了嗎！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일의 말 대로, 다른 부수적인 문제를 저울질하지 않을 정도라면 예삿일은 아니겠죠.","JPN":"カイルの言う通り、他の諸問題を無視するほどのことなら、ただ事ではないはず。","ENG":"As Kyle says, if it outweighs the side issues on the scale, this is no ordinary business.","TWN":"就像凱爾說的，如果不須衡量其他附帶問題，那應該是非同小可了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"말씀해주십시오, 대통령님.","JPN":"教えてください、大統領。","ENG":"Please, Mr. President, brief us.","TWN":"您請說吧，總統。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"얼마 전, 전세계적으로 일어난 최고 등급의 재난 현상…….","JPN":"この前、全世界的に発生した管理局最高ランクの災難現象……","ENG":"The highest-level disasters that broke out worldwide recently...","TWN":"不久前，全世界發生的最高等級災難現象……"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그것이 이전 클리포트 게임의 시작을 알렸던 허신과 같은 전조 현상이라면.","JPN":"それが以前のクリフォトゲームの幕開けを告げた、虚神のような前兆であるなら。","ENG":"If those are omens like the Hollow God that heralded the last Qliphoth Game...","TWN":"如果是像之前宣告逆卡巴拉遊戲開始的幻神一樣的前兆，"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이전 저희가 맞닥뜨린 재앙, 마왕이라는 신성 침식체가 움직이기 시작한 겁니까?","JPN":"過去に我々が直面した災難……魔王という神聖侵食体が動き出したのですか？","ENG":"Then has the disaster we faced before, the Divine C.O. entity called the Demon Lord, begun to move?","TWN":"難道是我們先前面臨的災難，那個叫魔王的神聖侵蝕體開始行動了嗎？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"말하지 않았나. 나도 갑작스레 연락을 받았을 뿐이야.","JPN":"言っただろう。私も急に連絡を受けただけだ。","ENG":"I already told you. I was only contacted out of the blue.","TWN":"我不是說過了嗎？我也只是突然接到消息。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"자세한 이야기는 관리국 사람에게 듣는 편이 좋겠군.","JPN":"詳細は管理局の人から聞いたほうがいいだろう。","ENG":"You should hear the details from the Administration.","TWN":"詳細的情況ˋ還是聽管理局的人說吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국 사람이라면…….","JPN":"管理局の人というと……","ENG":"If it is someone from the Administration...","TWN":"管理局的人……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마, 클리포트 게임 최종 국면에 모습을 드러냈던 최고 관리자를 말하는 겁니까?","JPN":"まさか、クリフォトゲームの最終局面で姿を見せた、最高管理者のことですか？","ENG":"Surely you mean the Supreme Administrator who appeared at the final phase of the Qliphoth Game?","TWN":"難道指的是在逆卡巴拉遊戲終局露面的最高管理者嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"아니. 하지만 얼굴 정도는 익숙한 사람일세.","JPN":"いや。しかし見知った顔ではあるだろう。","ENG":"No. But her face should be familiar.","TWN":"不，但算是面熟的人。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"일단은 챔버 관리국의 공인 카운터니까 말이야.","JPN":"一応チェンバー管理局の公認カウンターだからな。","ENG":"For now, she is an Official Administration Counter of the Chamber Administration.","TWN":"畢竟是密室管理局的公認制裁者。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 아아…. 합중국의 여러분, 들리시나요?","JPN":"あ、あー……合衆国の皆さん、聞こえてますか？","ENG":"Ah, ah... People of the States, can you hear me?","TWN":"啊、啊啊…合眾國的各位，聽得見嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제 이름은 예니카 시로코바.","JPN":"私はイェニカ・シロコバ。","ENG":"My name is Yanikka Shirokova.","TWN":"我的名字是耶妮卡·西羅克巴。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"챔버 관리국을 대표해서, 여러분에게 전하고 싶은 말이 있습니다!","JPN":"チェンバー管理局を代表して、皆さんに伝えたいことがあります！","ENG":"On behalf of the Chamber Administration, there is something I wish to tell you all.","TWN":"我代表密室管理局，有話想告訴各位！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};